import LeagueSVG from "../../assets/svgs/LeagueSVG";
import PanthersSVG from "../../assets/svgs/PanthersSVG";
import PlayersSVG from "../../assets/svgs/PlayersSVG";
import NagivationData from "../../data/nav/navigation";


const NavigationList = () =>
(
    <nav>
        {NagivationData.map((item, index) => {
            return (
                <Link to={item.path}>
                    <span>{item.title}</span>
                </Link>
            );
        })}
    </nav>
)

export default NavigationList;
